import React from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import TODOS from '../../mock/todos';
import './style.css';

function TodoItemPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  const todo = TODOS.find((item) => item.id === Number(id));

  if (!todo) {
    return (
      <div className="todo-item-page">
        <div className="todo-item-card">
          <p className="todo-item-badge">Todo Details</p>
          <h1>Todo Item Page</h1>
          <p className="todo-item-text">Todo item not found.</p>
          <button className="todo-item-button" onClick={() => navigate(-1)}>
            Go Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="todo-item-page">
      <div className="todo-item-card">
        <p className="todo-item-badge">Todo Details</p>
        <h1>Todo Item Page</h1>
        <p className="todo-item-text"><strong>Title:</strong> {todo.title}</p>
        <p className="todo-item-text"><strong>Description:</strong> {todo.title}</p>

        <p className="todo-item-text"><strong>Completed:</strong> {todo.completed ? 'Yes' : 'No'}</p>
        <button className="todo-item-button" onClick={() => navigate(-1)}>
          Go Back
        </button>
      </div>
    </div>
  );
}

export default TodoItemPage;
